import{_ as e,p as c,q as o,a1 as d}from"./framework-96b046e1.js";const a={},i=d('<p><code>Java</code> 是一个跨平台的编程语言，一般用户服务器编程、<code>Web</code> 开发、<code>Android</code> 开发等。</p><p><code>Java</code> 的语法与 <code>C/C++</code> 很想，比较容易学习。</p><h2 id="特性" tabindex="-1"><a class="header-anchor" href="#特性" aria-hidden="true">#</a> 特性</h2><ul><li><p><code>Java</code>语言是强制面向对象的，支持类之间的单继承，支持接口之间的多继承</p></li><li><p><code>Java</code>语言是分布式的。<code>Java</code>语言支持<code>Internet</code>应用的开发，在基本的`Java应用编程接口中有一个网络应用编程接口</p></li><li><p><code>Java</code>语言是健壮的。 <code>Java</code>的强类型机制、异常处理、垃圾的自动收集等是<code>Java</code>程序健壮性的重要保证</p></li><li><p><code>Java</code>语言是安全的。 <code>Java</code>通常被用在网络环境中，为此， <code>Java</code>提供了一个安全机制以防恶意代码的攻击。如：安全防范机制（类<code>ClassLoader</code>），如分配不同的名字空间以防替代本地的同名类、字节代码检查；</p></li><li><p><code>Java</code>语言是体系结构中立的。 <code>Java</code>程序（后缀为<code>java</code>的文件）在<code>Java</code>平台上被编译为体系结构中立的字节码格式（后缀为<code>class</code>的文件），然后可以在实现这个<code>Java</code>平台的任何系统中运行；</p></li><li><p>一个源文件中最多只能有一个 <code>public</code> 类。其它类的个数不限，如果源文件包含一个<code>public</code>类，则文件名必须按该类名命名</p></li></ul>',4),l=[i];function t(p,n){return c(),o("div",null,l)}const s=e(a,[["render",t],["__file","index.html.vue"]]);export{s as default};
